import React from "react";
import "./css/style.css";
import Hero from "./Hero";
import EmpowerToken from "./EmpowerToken";
import OurElite from "./OurElite";
import TopBlockChain from "./TopBlockChain";
import EssentialFeatures from "./EssentialFeatures";
import IcoBuild from "./IcoBuild";
import TrendingIndustry from "./TrendingIndustry";
import HireIconDev from "./HireIconDev";
import IcoBigCards from "./IcoBigCards";
import WhyChoose from "./WhyChoose";
import FaqSection from "./faq-section";

const IconDevelopmentCompanyScreen = (props) => {
  const { db } = props;

  return (
    <div id="ico-development-company">
      <Hero db={db} />
      <EmpowerToken />
      <OurElite />
      <TopBlockChain />
      <EssentialFeatures />
      <IcoBuild />
      <TrendingIndustry />
      <HireIconDev db={db} />
      <IcoBigCards />
      <WhyChoose db={db} />
      <FaqSection />
    </div>
  );
};

export default IconDevelopmentCompanyScreen;
