import React, { useState } from "react";

export const WhyContent = ({ data }) => {
  return (
    <div className="why-content item-start">
      <p className="about-p">{data.desc}</p>
    </div>
  );
};
const datas = [
  {
    id: 0,
    key: "Multi- Layer Security",
    desc: "As a trusted ICO development company, Justtry Technologies implements multi-layer security measures to protect every stage of your ICO platform. This includes SSL encryption, DDoS protection, firewall configuration, and secure data storage. Our layered approach safeguards user information, transactions, and platform access, minimizing threats and ensuring smooth performance throughout your ICO journey.",
  },
  {
    id: 1,
    key: "Performance Metrics",
    desc: "We integrate advanced performance tracking tools that monitor all key aspects of your ICO in real time. Metrics cover token distribution, transaction rates, investor activity, and platform load. With actionable insights, you can optimize decisions and maintain complete control over your ICO development process. Our system keeps you informed and aligned with your project goals at every stag",
  },
  {
    id: 2,
    key: "Paperless Operations",
    desc: "Our ICO development approach streamlines the process by eliminating unnecessary paperwork. From investor registration to fund management and reporting, everything is handled digitally through smart contracts and automated tools. This reduces delays, avoids manual errors, and simplifies compliance. At Justtry Technologies, we prioritize efficiency without compromising security or accuracy.",
  },
  {
    id: 3,
    key: "Smooth KYC Verification",
    desc: "We provide seamless KYC integration for quick and secure identity verification. Our systems comply with global regulations while offering a user-friendly experience. Features include document upload, real-time verification, and encrypted data handling. By simplifying onboarding, your ICO platform becomes accessible, reliable, and trusted by investors.",
  },
  {
    id: 4,
    key: "Token Loss Protection",
    desc: "Our ICO development model includes secure token handling mechanisms to prevent loss. This involves multi-signature wallets, backup procedures, and smart contract safety checks. These measures protect user assets, maintain transparency, and uphold your project’s credibility throughout the token sale process..",
  },
  {
    id: 5,
    key: "Hosting & Fund Administration",
    desc: "We provide high-performance hosting and secure fund management as part of our ICO services. Platforms run on robust servers with continuous monitoring, data protection, and load balancing. Fund storage and token sale management are fully transparent, allowing your team to focus on growth while the infrastructure ensures safe, uninterrupted operations.",
  },
];

const tabOptions = [
  { key: "Multi- Layer Security", label: "Multi- Layer Security", number: 1 },
  { key: "Performance Metrics", label: "Performance Metrics", number: 2 },
  { key: "Paperless Operations", label: "Paperless Operations", number: 3 },
  {
    key: "Smooth KYC Verification",
    label: "Smooth KYC Verification",
    number: 4,
  },
  { key: "Token Loss Protection", label: "Token Loss Protection", number: 5 },
  {
    key: "Hosting & Fund Administration",
    label: "Hosting & Fund Administration",
    number: 6,
  },
];

const EssentialFeatures = () => {
  const [selectedTab, setSelectedTab] = useState("Multi- Layer Security");

  return (
    <section className="essential-features-wrapper item-center">
      <div className="essential-feture-header item-center">
        <h2 className="about-h3 c-text-center md-c-text-start">
          Essential Features of Our{" "}
          <span className="gradient-text-bg">ICO Development Services</span>
        </h2>
        <p className="about-p">
          Our solutions cover every critical aspect of ICO development,
          equipping your project to attract investors and drive sustainable
          growth.
        </p>
      </div>
      <div className="essential-feature-selection-section">
        <div className="item-start essential-tab-buttons">
          {tabOptions.map((tab) => (
            <button
              key={tab.key}
              onClick={() => setSelectedTab(tab.key)}
              style={{
                background: selectedTab === tab.key ? "#212529" : "transparent",
                color: selectedTab === tab.key ? "#ffffffff" : "#212529",
              }}
              className="ico-tab-btn"
            >
              <span>
                {tab.number}. {tab.label}
              </span>
            </button>
          ))}
        </div>
        <div className="essential-ans-section">
          {datas
            .filter((data) => data.key === selectedTab)
            .map((data) => (
              <WhyContent key={data.id} data={data} />
            ))}
        </div>
      </div>
    </section>
  );
};

export default EssentialFeatures;
