import React from "react";
import { graphql } from "gatsby";
import { initializeApp } from "firebase/app";
import { getFirestore } from "firebase/firestore/lite";
// import Layout from "@components/layout";
// import BreadCrumb from "@components/common/breadcrumb";
import Seo from "@components/seo";
import { useLocation } from "@reach/router";
import IconDevelopmentCompanyScreen from "@screens/ico-development-company";
import Layout_v2 from "@components/layout_v2";
import BreadCrumbV2 from "@components/common/breadcrumb-v2";

const IcoDevelopmentCompany = (props) => {
  const app = initializeApp(props?.data?.site?.siteMetadata?.firestore);
  const db = getFirestore(app);
  const breadcrumbLinks = [
    { text: "Home", link: "/" },
    { text: "Ico Development Company", link: null },
  ];
  const { data } = props;
  const location = useLocation();
  const fileUrl =
    data?.icoDevelopmentCompanyImg?.childImageSharp?.gatsbyImageData?.images
      ?.fallback?.src;
  const validData = data?.allMetaJson?.nodes[0];
  const schemaMarkup = {
    "@context": "https://schema.org",
    "@graph": [
      {
        "@type": "Organization",

        name: "Justtry Technologies",
        url: "https://justtrytech.com",
        logo: "https://justtrytech.com/static/company_logo-a8a6f67b23da723440dd6bdb258ac7e8.svg",
        description:
          "Justtry Technology provides a complete solution of ICO development and secure token generation, smart contracts, and effective fundraising solutions of blockchain projects.",
        sameAs: [
          "https://www.linkedin.com/company/justtry-technologies",
          "https://twitter.com/justtrytech",
        ],
        email: "sales@justtrytech.com",
        telephone: "+91 9500139200",
        address: {
          "@type": "PostalAddress",
          streetAddress:
            "179/3, Kamarajar salai, (Near Tamilnadu Chamber of Commerce), Madurai – 625009.",
          addressLocality: "Madurai",
          addressCountry: "IN",
          addressRegion: "Tamilnadu",
          postalCode: "625009",
        },
        aggregateRating: {
          "@type": "AggregateRating",
          ratingValue: "4.8",
          reviewCount: "1458",
        },
      },
      {
        "@type": "FAQPage",

        mainEntity: [
          {
            "@type": "Question",
            name: "What does ICO mean?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "ICO stands for Initial Coin Offering, a fundraising method where blockchain projects raise capital by selling digital tokens to early investors.",
            },
          },
          {
            "@type": "Question",
            name: "How does ICO work?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "An ICO works by a blockchain project issuing and selling digital tokens to investors, usually in exchange for crypto or fiat, to fund development and growth.",
            },
          },
          {
            "@type": "Question",
            name: "What is ICO in India?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "In India, an ICO is a blockchain fundraising mechanism, in which tokens are sold to capitalists; however, it is in a regulatory gray space, with no legal framework or licensing.",
            },
          },
        ],
      },
    ],
  };

  return (
    <Layout_v2 db={db}>
      <Seo
        title={validData?.title}
        metaTitle={validData?.metaTitle}
        metaKeyword={validData?.metaKeyword}
        description={validData?.description}
        image={fileUrl}
        siteFirestore={data?.site?.siteMetadata?.firestore}
        slug={location.pathname.split("/")?.[1]}
        schemaMarkup={schemaMarkup}
      ></Seo>
      <BreadCrumbV2 items={breadcrumbLinks} />
      <main>
        <IconDevelopmentCompanyScreen db={db} />
      </main>
    </Layout_v2>
  );
};

export default IcoDevelopmentCompany;
export const queryData = graphql`
  query MyQuery {
    icoDevelopmentCompanyImg: file(
      relativePath: { eq: "ico-development-company.png" }
    ) {
      childImageSharp {
        gatsbyImageData
      }
    }
    site {
      siteMetadata {
        firestore {
          apiKey
          appId
          authDomain
          messagingSenderId
          projectId
          storageBucket
        }
      }
    }
    allMetaJson(filter: { slug: { eq: "ico-development-company" } }) {
      nodes {
        metaTitle
        metaKeyword
        title
        slug
        description
      }
    }
  }
`;
