import React from "react";
import { StaticImage } from "gatsby-plugin-image";
import { Link } from "@reach/router";
import TalkToUsNew from "@components/common/talk-to-us-new";

const Hero = ({ db }) => {
  return (
    <section className="ico-dev-hero-banner justify_between">
      <div className="item-start">
        <h1 className="about-h2-v2 font-black">
          <span className="gradient-text-bg">ICO Development</span> Company
        </h1>
        <p className="about-p">
          Fuel your business growth with our customized ICO development
          services. Using the latest technology, we guide you every step of the
          way to launch your ICO successfully.
        </p>
        <div className="buttons">
          <Link to="/contact-us" className="roll-button roll-btn">
            <span>View Live Demo</span>
          </Link>
          <TalkToUsNew
            db={db}
            label="Free Consultation"
            customClass="normal-roll-button normal-roll-btn"
          />
        </div>
      </div>
      <div className="main-image">
        <StaticImage
          src="../../styles/assets/images/ico-development/ico-hero-image.png"
          alt="ico-hero-image"
          fetchpriority="high"
          layout="constrained"
          quality={75}
          loading="eager"
          placeholder="none"
        />
      </div>
      <div className="mobile-image">
        <StaticImage
          src="../../styles/assets/images/ico-development/rocket-image.png"
          alt="rocket-image"
          fetchpriority="high"
          layout="constrained"
          quality={75}
          loading="eager"
          placeholder="none"
        />
      </div>
    </section>
  );
};

export default Hero;
