import React from "react";
import Faqv2 from "@components/common/faq-v2";

const FaqSection = () => {
  const cryptoMlmFaqData = [
    {
      question: "What is an ICO?",
      answer:
        "An ICO (Initial Coin Offering) is a fundraising method where blockchain projects sell digital tokens to investors. It helps startups raise capital quickly. Investors purchase tokens using cryptocurrency or fiat money.",
    },
    {
      question: "How does an ICO work?",
      answer:
        "Projects create and sell tokens through smart contracts on a blockchain. Investors buy these tokens hoping for future value or platform utility. The process is transparent and decentralized.",
    },
    {
      question: "What are the benefits of launching an ICO?",
      answer:
        "ICOs enable fast and borderless fundraising. They attract global investors without relying on banks or venture capital. Projects also build community support early.",
    },
    {
      question: "What happens after an ICO ends?",
      answer:
        "Tokens are distributed to investors after the sale. The project team focuses on development and platform launch. They may also list the tokens on crypto exchanges for trading.",
    },
  ];
  return (
    <section className="crypto-faq-section">
      <Faqv2 faqData={cryptoMlmFaqData} />
    </section>
  );
};

export default FaqSection;
