import React, { useState } from "react";

const IcoBigCards = () => {
  const [activeCard, setActiveCard] = useState(1);

  return (
    <section className="ico-bigcards-wrapper">
      <div className="ico-bigcards">
        <div
          id="first-card"
          className={`ico-card item-start ${activeCard === 1 ? "active" : ""}`}
          onMouseEnter={() => setActiveCard(1)}
        >
          <h3 className="about-h3">Pre-ICO Launch Services</h3>
          <p className="about-p">
            Our Pre-ICO services are designed to set the foundation for a
            successful token launch. We help you create a compelling project
            vision, define a clear roadmap, and design robust tokenomics
            tailored to your business model. Our team supports you in
            identifying potential partners and investors, recruiting key
            personnel, and developing impactful marketing strategies. We also
            focus on building and nurturing a strong community around your
            project, ensuring engagement and credibility from day one. By
            handling all essential pre-launch activities, we prepare your ICO
            platform to attract investors and maximize the chances of a
            successful crowdfunding campaign.
          </p>
        </div>
        <div
          id="second-card"
          className={`ico-card item-start ${activeCard === 2 ? "active" : ""}`}
          onMouseEnter={() => setActiveCard(2)}
          onMouseLeave={() => setActiveCard(1)}
        >
          <h3 className="about-h3">Post-ICO Launch Services</h3>
          <p className="about-p">
            With our post-ICO launch services, Justtry Technologies ensures your
            project continues to grow and thrive beyond the fundraising stage.
            We provide end-to-end support to help you secure investors,
            strengthen your product, and scale your business to reach critical
            mass. Our services include evaluating product architecture, ensuring
            efficient capital management, and implementing strategies for
            sustainable business growth. By combining technology-driven
            solutions with proven expertise, we position your ICO venture for
            long-term success in the evolving blockchain ecosystem.
          </p>
        </div>
      </div>
    </section>
  );
};

export default IcoBigCards;
