import TalkToUsNew from "@components/common/talk-to-us-new";
import { StaticImage } from "gatsby-plugin-image";
import React from "react";

const HireIconDev = ({ db }) => {
  return (
    <section className="hire-ico-dev-wrapper ">
      <div className="hire-ico-dev flex-center">
        <div className="item-start">
          <h2 className="about-h2 font-white">Hire ICO Developers</h2>
          <p className="about-p-two">
            Initial Coin Offerings (ICOs) provide entrepreneurs and developers
            with a powerful way to raise funds for their blockchain or
            cryptocurrency projects. This fundraising model has gained immense
            popularity because it allows startups to secure investments without
            requiring investors to purchase physical assets or build complex
            infrastructure. At Justtry Technologies, we are a leading ICO
            development company offering fully customizable ICO development
            services. Our team of skilled developers specializes in creating
            secure, scalable, and investor-friendly ICO platforms designed to
            help your project reach its full fundraising potential.
          </p>
          <TalkToUsNew
            db={db}
            label="Hire Now"
            customClass="normal-roll-button normal-roll-btn"
          />
        </div>
      </div>
      <StaticImage
        src="../../styles/assets/images/ico-development/ico-hire-image.png"
        alt="rocket-image"
        fetchpriority="high"
        layout="constrained"
        quality={75}
        loading="eager"
        placeholder="none"
      />
    </section>
  );
};

export default HireIconDev;
