import { StaticImage } from "gatsby-plugin-image";
import React from "react";

const EmpowerToken = () => {
  return (
    <section className="empower-token-wrapper">
      <div className="empower-token flex-center">
        <div className="item-start">
          <h2 className="about-h3 font-white">
            Empower Your Token, Empower Your Future – ICO Development Made
            Simple
          </h2>
          <p className="about-p">
            Partner with Justtry Technologies to unlock the full potential of
            your startup’s fundraising. Our expert ICO development services are
            crafted to ensure your campaigns achieve optimal results, helping
            you secure the capital needed for your business growth. With a
            skilled team specializing in innovative, cutting-edge solutions, we
            drive success in the fast-paced world of Initial Coin Offerings.
          </p>
        </div>
      </div>
      <div className="bottom-image">
        <StaticImage
          src="../../styles/assets/images/ico-development/rocket-image.png"
          alt="rocket-image"
          fetchpriority="high"
          layout="constrained"
          quality={75}
          loading="eager"
          placeholder="none"
        />
      </div>
    </section>
  );
};

export default EmpowerToken;
